SELECT 
FROM AI_SUGGESTION s
JOIN AI_ANALYSIS_RUN r ON r.analysis_run_id = s.analysis_run_id
WHERE r.trip_id = #{tripId}

    AND s.status = #{status}

ORDER BY s.created_at DESC, s.ai_suggestion_id DESC

SELECT 
FROM AI_SUGGESTION s
JOIN AI_ANALYSIS_RUN r ON r.analysis_run_id = s.analysis_run_id
WHERE r.trip_id = #{tripId}
  AND s.ai_suggestion_id = #{suggestionId}
FOR UPDATE
